import{_ as d,o as a,c as e,ah as r}from"./chunks/framework.BNo2o5Ln.js";const b=JSON.parse('{"title":"NoSQL","description":"","frontmatter":{"title":"NoSQL","order":30},"headers":[],"relativePath":"server/db/nosql/index.md","filePath":"server/db/nosql/index.md"}'),i={name:"server/db/nosql/index.md"};function l(o,t,s,n,h,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="非关系型数据库服务" tabindex="-1">非关系型数据库服务 <a class="header-anchor" href="#非关系型数据库服务" aria-label="Permalink to “非关系型数据库服务”">​</a></h1><p>非关系型数据库是为了应对高并发、海量数据和非结构化数据存储而产生的数据库体系。它们突破了关系数据库的 ACID 限制，以 CAP 定理为指导，在一致性、可用性和分区容错性之间做出不同的权衡。</p><h2 id="内容概览" tabindex="-1">内容概览 <a class="header-anchor" href="#内容概览" aria-label="Permalink to “内容概览”">​</a></h2><p>本章节从实现者的角度深入剖析各类 NoSQL 数据库的底层原理，内容包括：</p><ul><li><strong>Redis 实现</strong>：单线程模型、数据结构实现、RDB/AOF 持久化、主从复制、集群架构</li><li><strong>MongoDB 实现</strong>：文档模型、WiredTiger 存储引擎、复制集、分片集群、聚合管道</li><li><strong>Elasticsearch 实现</strong>：倒排索引、FST 压缩、分片架构、分布式协调、查询处理</li><li><strong>Neo4j 实现</strong>：标签属性图、存储引擎、Schema 索引、Cypher 查询语言</li><li><strong>Milvus 实现</strong>：向量检索基础、IVF/HNSW 索引、存算分离架构</li><li><strong>消息队列实现</strong>：Kafka 存储机制、RabbitMQ 交换机、可靠性保证、消费语义</li></ul><h2 id="数据库分类" tabindex="-1">数据库分类 <a class="header-anchor" href="#数据库分类" aria-label="Permalink to “数据库分类”">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>代表产品</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>键值存储</td><td>Redis</td><td>高性能、简单结构</td><td>缓存、会话存储</td></tr><tr><td>文档存储</td><td>MongoDB</td><td>灵活 Schema、嵌套文档</td><td>内容管理、产品目录</td></tr><tr><td>搜索引擎</td><td>Elasticsearch</td><td>全文检索、复杂查询</td><td>日志分析、站内搜索</td></tr><tr><td>图数据库</td><td>Neo4j</td><td>关系遍历、图算法</td><td>社交网络、知识图谱</td></tr><tr><td>向量数据库</td><td>Milvus</td><td>相似度搜索、高维索引</td><td>图像检索、推荐系统</td></tr><tr><td>消息队列</td><td>Kafka/RabbitMQ</td><td>异步处理、解耦</td><td>日志收集、事件驱动</td></tr></tbody></table><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to “学习路径”">​</a></h2><p>建议按照以下顺序学习：</p><ol><li>先理解 NoSQL 与关系数据库的区别和权衡</li><li>学习 Redis 的内存数据结构和持久化机制</li><li>深入 MongoDB 的文档模型和分片架构</li><li>掌握 Elasticsearch 的倒排索引和分布式协调</li><li>了解图数据库和向量数据库的专用场景</li><li>研究消息队列的可靠性和消费语义</li></ol>',10)])])}const p=d(i,[["render",l]]);export{b as __pageData,p as default};
